#include <stdio.h>

void solve() {
    int n, d;
    scanf("%d %d", &d, &n);
    int ans = n;
    for (int i = 1; i <= d; i++) {
        ans = ans * (ans + 1) / 2;
    }
    printf("%d\n", ans);
}

int main() {
    int test;
    scanf("%d", &test);
    while (test--) {
        solve();
    }
    return 0;
}

code.Java:
import java.util.Scanner;

public class Main {

    public static void solve(Scanner sc) {
        int d = sc.nextInt();  
        int n = sc.nextInt(); 
        int ans = n;
        for (int i = 1; i <= d; i++) {
            ans = ans * (ans + 1) / 2;
        }
        System.out.println(ans);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int test = sc.nextInt();  
        while (test-- > 0) {
            solve(sc); 
        }
        sc.close();
    }
}

