function sum(N) {
    // Calculate the sum of the first N natural numbers
    return (N * (N + 1)) / 2;
}

function Ppsum(input) {
    // Split the input into an array of test cases
    const testCases = input.trim().split('\n').slice(1); // Remove the first line (number of test cases)

    // Process each test case
    for (const testCase of testCases) {
        // Parse the integers D and N for the current test case
        const [D, N] = testCase.split(' ').map(Number);

        // Apply the sum function D times
        let result = N;
        for (let i = 0; i < D; i++) {
            result = sum(result);
        }

        // Output the result for the current test case
        console.log(result);
    }
}

